const cfg = $('Set API and Keyword Parameters').first().json;
const rows = $input.all();

function normalizeItems(root) {
  const items = Array.isArray(root?.data?.items) ? root.data.items : [];

  return items.map((item, index) => ({
    index: index + 1,
    text: item?.text ?? '',
    searchType: item?.search_type ?? '',
    suggestionType: item?.type ?? '',
    description: item?.desc ?? '',
    link: item?.link ?? '',
    isIntervened: Boolean(item?.is_intervened ?? false),
    highlightFlags: Array.isArray(item?.highlight_flags) ? item.highlight_flags : []
  }));
}

return rows.map((item, index) => {
  const root = item.json || {};
  const normalizedItems = normalizeItems(root);

  const noteSuggestions = normalizedItems
    .filter(entry => entry.searchType === 'notes')
    .map(entry => entry.text)
    .filter(Boolean);

  const goodsSuggestions = normalizedItems
    .filter(entry => entry.searchType === 'goods')
    .map(entry => ({
      text: entry.text,
      description: entry.description,
      suggestionType: entry.suggestionType
    }))
    .filter(entry => entry.text);

  const allSuggestionTexts = normalizedItems
    .map(entry => entry.text)
    .filter(Boolean);

  return {
    json: {
      keyword: cfg.keyword || '',
      suggestionCount: normalizedItems.length,
      noteSuggestionCount: noteSuggestions.length,
      goodsSuggestionCount: goodsSuggestions.length,
      noteSuggestions,
      goodsSuggestions,
      allSuggestionTexts,
      items: normalizedItems,
      wordRequestId: root?.data?.word_request_id ?? '',
      searchCplId: root?.data?.search_cpl_id ?? '',
      requestResult: root?.data?.result ?? {},
      sourceNode: 'Get Xiaohongshu Keyword Suggestions',
      responseIndex: index + 1,
      raw: root
    }
  };
});
